def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        if ratio > 2:
            penalty_sum = 0
            for j in range(1, int(np.ceil(ratio))+2):
                penalty_term = ((ratio - j) ** 3) / j
                penalty_sum += penalty_term
            priority = penalty_sum + ratio ** 2
        elif 1 < ratio <= 2:
            priority = (ratio - 1) * 10 + np.exp(ratio - 1)
            for m in range(1, 5):
                priority += ((-1) ** m) * np.sin(ratio * m) / m
        elif 0.7 <= ratio <= 1:
            priority = -np.log(ratio) * 3
            adjustment = 0
            for n in range(1, 4):
                adjustment += ((0.8 - ratio) ** n) * n * 0.1
            priority += adjustment
        elif 0.3 <= ratio < 0.7:
            p = 0
            for k in range(1, 6):
                p += (0.5 - ratio) ** k * (k % 3 + 1) * 0.2
            priority = p + 0.5 / (ratio + 0.1)
        else:
            priority = 5
            for q in range(1, 4):
                priority -= np.log1p(bin_cap) * q / (item + q)
        priorities[i] = priority
    return priorities
